// SubmitUserDataInput is the resolver for the submitUserDataInput field.
func (r *mutationResolver) SubmitUserDataInput(ctx context.Context, input model.SubmitUserDataInputInput) (*model.SubmitUserDataInputResponse, error) {
	req := request.ForContext(ctx)

	workflowClient, err := r.workflowRouter.GetClient(ctx, req.MutationTenantID().String())
	if err != nil || workflowClient == nil {
		return nil, ErrInvalidWorkflowClient
	}

	executionInfo, err := workflowClient.GetWorkflowExecutionInfo(ctx, input.WorkflowID, input.WorkflowRunID)
	if err != nil {
		return nil, err
	}

	if executionInfo.GetStatus() != enums.WORKFLOW_EXECUTION_STATUS_RUNNING {
		return nil, ErrWorkflowNotRunning
	}

	var updateResult map[string]any
	if err := workflowClient.UpdateWorkflow(ctx, input.WorkflowID, input.WorkflowRunID,
		input.Name, input.Data, &updateResult,
	); err != nil {
		return nil, err
	}

	return &model.SubmitUserDataInputResponse{
		Result: updateResult,
		Workflow: &model.TemporalWorkflow{
			Type:  executionInfo.GetType().GetName(),
			ID:    executionInfo.GetExecution().GetWorkflowId(),
			RunID: executionInfo.GetExecution().GetRunId(),
		},
	}, nil
}

// CurrentUserDataInput is the resolver for the currentUserDataInput field.
